import { decompressBulk, type BulkImportData } from "~/factory/importexport/importexport";

/**
 * export string for the welcome factory.
 * Generated by exporting the factory from the running app and pasting the result here.
 */
const TEMPLATE_FACTORY =
  "";

/**
 * Decompress and unminify the embedded template factory.
 * Returns BulkImportData ready to pass to bulkImport().
 */
export async function loadTemplateFactory(): Promise<BulkImportData> {
  return decompressBulk(TEMPLATE_FACTORY);
}
